css:
@page { size: 80mm 297mm; margin: 5mm; }
body { font-family: 'Courier New', monospace; font-size: 9pt; color: #000; }
.header { text-align: center; border-bottom: 1px dotted #000; padding-bottom: 5px; margin-bottom: 8px; }
.header h1 { font-size: 12pt; margin: 0; }
.header .company-desc { font-size: 8pt; }
.receipt-title { text-align: center; font-weight: bold; font-size: 11pt; margin: 5px 0; }
.info { font-size: 8pt; margin: 5px 0; }
table.items { width: 100%; font-size: 8pt; border-collapse: collapse; }
table.items th { border-bottom: 1px dotted #000; padding: 3px 2px; text-align: left; }
table.items td { padding: 2px; }
table.items .num { text-align: right; }
.totals { width: 100%; font-size: 8pt; margin-top: 5px; border-top: 1px dotted #000; }
.totals td { padding: 2px; }
.footer { text-align: center; font-size: 7pt; margin-top: 10px; border-top: 1px dotted #000; padding-top: 5px; }
